class Solution:
    def reverseWords(self, s: str) -> str:
        return " ".join(w[::-1] for w in s.split(" "))

solutions.cpp:
class Solution {
public:
    string reverseWords(string s) {
        for (int i = 0; i < (int)s.size(); i++) {
            int j = i;
            while (j < (int)s.size() && s[j] != ' ') j++;
            reverse(s.begin()+i, s.begin()+j);
            i = j;
        }
        return s;
    }
};
